include '../config.php';
require_once __DIR__ . '/admin_audit.php';
if (empty($_SESSION['csrf_token'])) { $_SESSION['csrf_token'] = bin2hex(random_bytes(32)); }
$csrf_token = (string)$_SESSION['csrf_token'];
$admin_id = (int)$_SESSION['user_id'];
$current_admin_name = (string)($_SESSION['username'] ?? 'Admin');
$current_admin_role = (string)($_SESSION['role'] ?? 'admin');

$conn->query("CREATE TABLE IF NOT EXISTS live_chat_messages (id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NOT NULL,sender_role ENUM('user','admin') NOT NULL,message TEXT NOT NULL,is_read TINYINT(1) NOT NULL DEFAULT 0,delivered_at TIMESTAMP NULL DEFAULT NULL,seen_at TIMESTAMP NULL DEFAULT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,INDEX idx_live_chat_user_read (user_id,sender_role,is_read),FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE)");
$conn->query("CREATE TABLE IF NOT EXISTS admin_dashboard_notes (id INT AUTO_INCREMENT PRIMARY KEY,admin_id INT NOT NULL UNIQUE,note_text TEXT NOT NULL,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,FOREIGN KEY (admin_id) REFERENCES users(id) ON DELETE CASCADE)");
rbj_ensure_admin_activity_logs_table($conn);

function s(mysqli $c, string $q, string $f='count'): float { $r=$c->query($q); if(!($r instanceof mysqli_result))return 0; $row=$r->fetch_assoc(); $r->free(); return (float)($row[$f]??0); }
function t(mysqli $c, string $name): bool { $safe=$c->real_escape_string($name); $r=$c->query("SHOW TABLES LIKE '{$safe}'"); if(!($r instanceof mysqli_result))return false; $ok=$r->num_rows>0; $r->free(); return $ok; }
function trend(float $a,float $b): array { if($b<=0)return $a>0?['l'=>'New','c'=>'up']:['l'=>'No change','c'=>'flat']; $p=(($a-$b)/$b)*100; if($p>0)return ['l'=>'+'.round($p,1).'%', 'c'=>'up']; if($p<0)return ['l'=>round($p,1).'%', 'c'=>'down']; return ['l'=>'0%','c'=>'flat']; }
function snap(mysqli $c): array {
  $hasPay=t($c,'payments'); $hasProof=t($c,'payment_proofs');
  $stock=false; $sc=$c->query("SHOW COLUMNS FROM customization_templates LIKE 'stock_quantity'"); if($sc instanceof mysqli_result){$stock=$sc->num_rows>0; $sc->free();}
  $o=[
    'user_count'=>(int)s($c,"SELECT COUNT(*) count FROM users"),
    'order_count'=>(int)s($c,"SELECT COUNT(*) count FROM orders"),
    'pending_orders'=>(int)s($c,"SELECT COUNT(*) count FROM orders WHERE status IN ('pending','to_pay')"),
    'to_ship_orders'=>(int)s($c,"SELECT COUNT(*) count FROM orders WHERE status IN ('in_progress','to_ship')"),
    'to_receive_orders'=>(int)s($c,"SELECT COUNT(*) count FROM orders WHERE status='to_receive'"),
    'pending_feedbacks'=>(int)s($c,"SELECT COUNT(*) count FROM feedback WHERE status='submitted'"),
    'unread_live_chat'=>(int)s($c,"SELECT COUNT(*) count FROM live_chat_messages WHERE sender_role='user' AND is_read=0"),
    'pending_payment_proofs'=>0,'rejected_payment_proofs'=>0,'low_stock_count'=>0,
    'today_sales'=>0.0,'week_sales'=>0.0,'month_sales'=>0.0,'method_split'=>[],'has_payments'=>$hasPay
  ];
  if($hasPay){
    $o['today_sales']=s($c,"SELECT COALESCE(SUM(amount),0) count FROM payments WHERE status='completed' AND DATE(payment_date)=CURDATE()");
    $o['week_sales']=s($c,"SELECT COALESCE(SUM(amount),0) count FROM payments WHERE status='completed' AND payment_date>=DATE_SUB(CURDATE(), INTERVAL 7 DAY)");
    $o['month_sales']=s($c,"SELECT COALESCE(SUM(amount),0) count FROM payments WHERE status='completed' AND YEAR(payment_date)=YEAR(CURDATE()) AND MONTH(payment_date)=MONTH(CURDATE())");
    $mr=$c->query("SELECT payment_method, COUNT(*) total FROM payments WHERE status='completed' AND payment_date>=DATE_SUB(CURDATE(), INTERVAL 30 DAY) GROUP BY payment_method ORDER BY total DESC");
    if($mr instanceof mysqli_result){while($row=$mr->fetch_assoc()){$o['method_split'][]=['method'=>(string)($row['payment_method']??'unknown'),'count'=>(int)($row['total']??0)];}$mr->free();}
  }
  if($hasProof){$o['pending_payment_proofs']=(int)s($c,"SELECT COUNT(*) count FROM payment_proofs WHERE status='pending'");$o['rejected_payment_proofs']=(int)s($c,"SELECT COUNT(*) count FROM payment_proofs WHERE status='rejected'");}
  if($stock){$o['low_stock_count']=(int)s($c,"SELECT COUNT(*) count FROM customization_templates WHERE is_active=1 AND stock_quantity<=5");}
  return $o;
}

if(isset($_GET['ajax']) && $_GET['ajax']==='summary'){
  header('Content-Type: application/json; charset=UTF-8');
  $x=snap($conn); $o=[]; $rr=$conn->query("SELECT o.id,u.username,o.created_at FROM orders o JOIN users u ON u.id=o.user_id ORDER BY o.created_at DESC LIMIT 4"); if($rr instanceof mysqli_result){while($r=$rr->fetch_assoc())$o[]=$r; $rr->free();}
  echo json_encode(['ok'=>true,'snapshot'=>$x,'recent_orders'=>$o,'feedback_today'=>(int)s($conn,"SELECT COUNT(*) count FROM feedback WHERE DATE(created_at)=CURDATE()")]); $conn->close(); exit();
}
if(isset($_GET['export'])){
  $e=(string)$_GET['export']; $allow=['orders','feedback','inventory','audit']; if(in_array($e,$allow,true)){
    header('Content-Type: text/csv; charset=UTF-8'); header('Content-Disposition: attachment; filename="rbj_'.$e.'_'.date('Ymd_His').'.csv"'); $out=fopen('php://output','w');
    if($out!==false){
      if($e==='orders'){ fputcsv($out,['Order ID','User','Email','Status','Created']); $r=$conn->query("SELECT o.id,u.username,u.email,o.status,o.created_at FROM orders o JOIN users u ON u.id=o.user_id ORDER BY o.created_at DESC"); if($r instanceof mysqli_result){while($row=$r->fetch_assoc())fputcsv($out,[$row['id'],$row['username'],$row['email'],$row['status'],$row['created_at']]); $r->free();}}
      elseif($e==='feedback'){ fputcsv($out,['ID','User','Rating','Status','Created','Feedback']); $r=$conn->query("SELECT f.id,u.username,f.rating,f.status,f.created_at,f.feedback FROM feedback f JOIN users u ON u.id=f.user_id ORDER BY f.created_at DESC"); if($r instanceof mysqli_result){while($row=$r->fetch_assoc())fputcsv($out,[$row['id'],$row['username'],$row['rating'],$row['status'],$row['created_at'],$row['feedback']]); $r->free();}}
      elseif($e==='inventory'){ fputcsv($out,['Product ID','Name','Category','Stock','Active']); $r=$conn->query("SELECT id,name,category,COALESCE(stock_quantity,0) stock_quantity,is_active FROM customization_templates ORDER BY stock_quantity ASC,name ASC"); if($r instanceof mysqli_result){while($row=$r->fetch_assoc())fputcsv($out,[$row['id'],$row['name'],$row['category'],$row['stock_quantity'],(int)$row['is_active']===1?'Yes':'No']); $r->free();}}
      else { fputcsv($out,['Timestamp','Admin','Action','Entity','Entity ID']); $r=$conn->query("SELECT l.created_at,u.username,l.action,l.entity_type,l.entity_id FROM admin_activity_logs l JOIN users u ON u.id=l.admin_id ORDER BY l.created_at DESC LIMIT 2000"); if($r instanceof mysqli_result){while($row=$r->fetch_assoc())fputcsv($out,[$row['created_at'],$row['username'],$row['action'],$row['entity_type'],$row['entity_id']]); $r->free();}}
      fclose($out);
    }
    rbj_admin_log($conn,$admin_id,'export_report','dashboard',null,['type'=>$e]); $conn->close(); exit();
  }
}

$msg=''; $err='';
if($_SERVER['REQUEST_METHOD']==='POST' && isset($_POST['save_dashboard_note'])){
  if(!hash_equals($csrf_token,(string)($_POST['csrf_token']??''))){$err='Invalid request token.';} else {
    $note=trim((string)($_POST['dashboard_note']??'')); $st=$conn->prepare("INSERT INTO admin_dashboard_notes (admin_id,note_text) VALUES (?,?) ON DUPLICATE KEY UPDATE note_text=VALUES(note_text)");
    if($st){$st->bind_param('is',$admin_id,$note); if($st->execute()){$msg='Dashboard note saved.'; rbj_admin_log($conn,$admin_id,'save_dashboard_note','dashboard',null,['length'=>mb_strlen($note)]);} else {$err='Failed to save note.';} $st->close();}
  }
}

$x=snap($conn);
$orders7=s($conn,"SELECT COUNT(*) count FROM orders WHERE created_at>=DATE_SUB(CURDATE(), INTERVAL 7 DAY)");
$ordersPrev7=s($conn,"SELECT COUNT(*) count FROM orders WHERE created_at>=DATE_SUB(CURDATE(), INTERVAL 14 DAY) AND created_at<DATE_SUB(CURDATE(), INTERVAL 7 DAY)");
$users30=s($conn,"SELECT COUNT(*) count FROM users WHERE created_at>=DATE_SUB(CURDATE(), INTERVAL 30 DAY)");
$usersPrev30=s($conn,"SELECT COUNT(*) count FROM users WHERE created_at>=DATE_SUB(CURDATE(), INTERVAL 60 DAY) AND created_at<DATE_SUB(CURDATE(), INTERVAL 30 DAY)");
$monthPrev=$x['has_payments']?s($conn,"SELECT COALESCE(SUM(amount),0) count FROM payments WHERE status='completed' AND YEAR(payment_date)=YEAR(DATE_SUB(CURDATE(), INTERVAL 1 MONTH)) AND MONTH(payment_date)=MONTH(DATE_SUB(CURDATE(), INTERVAL 1 MONTH))"):0;
$trOrders=trend($orders7,$ordersPrev7); $trUsers=trend($users30,$usersPrev30); $trSales=trend((float)$x['month_sales'],$monthPrev);
$recentOrders=[]; $rr=$conn->query("SELECT o.id,o.status,o.created_at,u.username FROM orders o JOIN users u ON u.id=o.user_id ORDER BY o.created_at DESC LIMIT 5"); if($rr instanceof mysqli_result){while($r=$rr->fetch_assoc())$recentOrders[]=$r; $rr->free();}
$feedbackToday=(int)s($conn,"SELECT COUNT(*) count FROM feedback WHERE DATE(created_at)=CURDATE()");
$low=[]; $lr=$conn->query("SELECT name,category,COALESCE(stock_quantity,0) stock_quantity FROM customization_templates WHERE is_active=1 AND COALESCE(stock_quantity,0)<=5 ORDER BY stock_quantity ASC,name ASC LIMIT 6"); if($lr instanceof mysqli_result){while($r=$lr->fetch_assoc())$low[]=$r; $lr->free();}
$top=[]; if(t($conn,'order_items')){$tr=$conn->query("SELECT t.name,SUM(oi.quantity) units,SUM(oi.quantity*oi.price) revenue FROM order_items oi JOIN customization_templates t ON t.id=oi.template_id JOIN orders o ON o.id=oi.order_id WHERE o.created_at>=DATE_SUB(CURDATE(), INTERVAL 30 DAY) GROUP BY t.id,t.name ORDER BY revenue DESC LIMIT 5"); if($tr instanceof mysqli_result){while($r=$tr->fetch_assoc())$top[]=$r; $tr->free();}}
$obm=$conn->query("SELECT DATE_FORMAT(created_at,'%Y-%m') month,COUNT(*) count FROM orders WHERE created_at>=DATE_SUB(CURDATE(), INTERVAL 12 MONTH) GROUP BY DATE_FORMAT(created_at,'%Y-%m') ORDER BY month");
$ubm=$conn->query("SELECT DATE_FORMAT(created_at,'%Y-%m') month,COUNT(*) count FROM users WHERE created_at>=DATE_SUB(CURDATE(), INTERVAL 12 MONTH) GROUP BY DATE_FORMAT(created_at,'%Y-%m') ORDER BY month");
$fbm=$conn->query("SELECT DATE_FORMAT(created_at,'%Y-%m') month,COUNT(*) count FROM feedback WHERE created_at>=DATE_SUB(CURDATE(), INTERVAL 12 MONTH) GROUP BY DATE_FORMAT(created_at,'%Y-%m') ORDER BY month");
$audit=[]; $ar=$conn->query("SELECT l.created_at,u.username,l.action,l.entity_type,l.entity_id FROM admin_activity_logs l JOIN users u ON u.id=l.admin_id ORDER BY l.created_at DESC LIMIT 8"); if($ar instanceof mysqli_result){while($r=$ar->fetch_assoc())$audit[]=$r; $ar->free();}
$note=''; $ns=$conn->prepare("SELECT note_text FROM admin_dashboard_notes WHERE admin_id=? LIMIT 1"); if($ns){$ns->bind_param('i',$admin_id); $ns->execute(); $row=$ns->get_result()->fetch_assoc(); $note=(string)($row['note_text']??''); $ns->close();}
$conn->close();
?>
<!doctype html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Admin Dashboard</title><link href="https://unpkg.com/boxicons@2.1.4/css/boxicons.min.css" rel="stylesheet"><link href="assets/admin-enhancements.css" rel="stylesheet"><script src="https://cdn.jsdelivr.net/npm/chart.js"></script><style>body{margin:0;font-family:Arial,sans-serif;background:#f4f6f8}.wrap{display:flex;min-height:100vh}.main{flex:1;padding:20px}.top{display:flex;justify-content:space-between;flex-wrap:wrap;gap:8px}.tool a,.tool button{font-size:12px;padding:8px 9px;border:1px solid #d8dde6;background:#fff;border-radius:8px;text-decoration:none;color:#1f2933;cursor:pointer}.grid{display:grid;grid-template-columns:2fr 1fr;gap:12px}.stats{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:10px}.card,.panel,.chart{background:#fff;border:1px solid #e9edf3;border-radius:12px;padding:12px;box-shadow:0 2px 8px rgba(0,0,0,.06)}.card{text-decoration:none;color:inherit}.label{font-size:11px;text-transform:uppercase;color:#6b7785}.val{font-size:28px;font-weight:700;margin:6px 0}.sub{font-size:12px;color:#7b8794}.tr{display:inline-block;padding:2px 8px;border-radius:999px;font-size:11px;font-weight:700}.up{background:#d5f5e3;color:#136c38}.down{background:#fde2e2;color:#9a2b2b}.flat{background:#edf2f7;color:#4c5a67}.stack{display:grid;gap:10px}.two,.charts{display:grid;grid-template-columns:1.2fr 1fr;gap:12px;margin-top:12px}ul{list-style:none;padding:0;margin:0}li{padding:8px 0;border-bottom:1px solid #edf1f5;font-size:14px}li:last-child{border-bottom:0}small{display:block;color:#7b8794}table{width:100%;border-collapse:collapse}th,td{padding:7px 4px;border-bottom:1px solid #edf1f5;text-align:left;font-size:13px}th{font-size:11px;color:#6b7785;text-transform:uppercase}.h{height:240px}textarea{width:100%;min-height:100px;border:1px solid #d8dde6;border-radius:8px;padding:8px}#root.compact .card,#root.compact .panel,#root.compact .chart{padding:9px}#root.compact li{padding:6px 0}@media(max-width:1100px){.grid,.two,.charts{grid-template-columns:1fr}}</style></head><body><div class="wrap"><aside class="side"><div class="logo"><a class="admin-logo-link" href="/rbjsystem/ADMIN/dashboard_admin.php"><img src="/rbjsystem/rbjlogo.png" alt="RBJ"></a></div><div class="admin-identity-card"><div class="admin-identity-label">Logged In As</div><div class="admin-identity-name"><?php echo htmlspecialchars($current_admin_name, ENT_QUOTES, 'UTF-8'); ?></div><div class="admin-identity-role"><?php echo htmlspecialchars($current_admin_role, ENT_QUOTES, 'UTF-8'); ?></div></div><a class="a" href="/rbjsystem/ADMIN/dashboard_admin.php">Dashboard</a><a href="/rbjsystem/ADMIN/users_admin.php">Users</a><a href="/rbjsystem/ADMIN/orders_admin.php">Orders</a><a href="/rbjsystem/ADMIN/products_admin.php">Products</a><a href="/rbjsystem/ADMIN/vouchers_admin.php">Vouchers</a><a href="/rbjsystem/ADMIN/feedback_admin.php">Feedbacks</a><a href="/rbjsystem/ADMIN/admin_support.php">Support</a>
      <a href="/rbjsystem/ADMIN/activity_logs_admin.php">Activity Logs</a>
      <a href="/rbjsystem/ADMIN/live_chat.php">Live Chat</a><a href="/rbjsystem/logout.php">Logout</a></aside><main class="main" id="root"><div class="top"><div><h1>Admin Dashboard</h1><div class="sub">Actionable KPI, real-time ops queue, finance/inventory insights, exports, and audit log.</div></div><div class="tool"><a href="?export=orders">Export Orders</a> <a href="?export=inventory">Export Inventory</a> <a href="?export=feedback">Export Feedback</a> <a href="?export=audit">Export Audit</a> <button id="density">Compact</button> <button id="refresh">Refresh</button></div></div><div class="grid"><div class="stats"><a class="card" href="/rbjsystem/ADMIN/users_admin.php"><div class="label">Users</div><div class="val" data-k="user_count"><?php echo number_format($x['user_count']); ?></div><div class="sub">New 30d: <?php echo number_format((int)$users30); ?></div><span class="tr <?php echo $trUsers['c']; ?>"><?php echo $trUsers['l']; ?></span></a><a class="card" href="/rbjsystem/ADMIN/orders_admin.php"><div class="label">Orders</div><div class="val" data-k="order_count"><?php echo number_format($x['order_count']); ?></div><div class="sub">Last 7d: <?php echo number_format((int)$orders7); ?></div><span class="tr <?php echo $trOrders['c']; ?>"><?php echo $trOrders['l']; ?></span></a><a class="card" href="/rbjsystem/ADMIN/orders_admin.php?status=to_ship"><div class="label">To Ship</div><div class="val" data-k="to_ship_orders"><?php echo number_format($x['to_ship_orders']); ?></div></a><a class="card" href="/rbjsystem/ADMIN/orders_admin.php?status=to_receive"><div class="label">To Receive</div><div class="val" data-k="to_receive_orders"><?php echo number_format($x['to_receive_orders']); ?></div></a></div><div class="stack"><div class="panel"><div class="label">Sales Today</div><div class="val" data-k="today_sales">PHP <?php echo number_format($x['today_sales'],2); ?></div></div><div class="panel"><div class="label">Sales This Month</div><div class="val" data-k="month_sales">PHP <?php echo number_format($x['month_sales'],2); ?></div><span class="tr <?php echo $trSales['c']; ?>"><?php echo $trSales['l']; ?></span></div><div class="panel"><div class="label">Pending Orders</div><div class="val" data-k="pending_orders"><?php echo number_format($x['pending_orders']); ?></div></div><div class="panel"><div class="label">Unread Chat</div><div class="val" data-k="unread_live_chat">PHP <?php echo number_format($x['unread_live_chat']); ?></div></div></div></div><div class="two"><section class="panel"><h3>Recent Activity</h3><ul id="activity"><?php foreach($recentOrders as $o): ?><li>Order #<?php echo (int)$o['id']; ?> from <?php echo htmlspecialchars($o['username']); ?><small><?php echo htmlspecialchars($o['status']); ?> | <?php echo date('M j, Y g:i A', strtotime($o['created_at'])); ?></small></li><?php endforeach; ?><li><?php echo (int)$feedbackToday; ?> feedback submission(s) today<small><a href="/rbjsystem/ADMIN/feedback_admin.php">Open moderation</a></small></li></ul></section><section class="panel"><h3>Needs Attention</h3><ul id="attention"><?php if($x['pending_orders']>0):?><li><a href="/rbjsystem/ADMIN/orders_admin.php?status=to_pay"><?php echo $x['pending_orders']; ?> pending order(s)</a></li><?php endif; ?><?php if($x['pending_payment_proofs']>0):?><li><a href="/rbjsystem/ADMIN/orders_admin.php?status=to_pay"><?php echo $x['pending_payment_proofs']; ?> pending payment proof(s)</a></li><?php endif; ?><?php if($x['rejected_payment_proofs']>0):?><li><a href="/rbjsystem/ADMIN/orders_admin.php?status=to_pay"><?php echo $x['rejected_payment_proofs']; ?> rejected proof(s)</a></li><?php endif; ?><?php if($x['pending_feedbacks']>0):?><li><a href="/rbjsystem/ADMIN/feedback_admin.php"><?php echo $x['pending_feedbacks']; ?> feedback pending review</a></li><?php endif; ?><?php if($x['low_stock_count']>0):?><li><a href="/rbjsystem/ADMIN/products_admin.php"><?php echo $x['low_stock_count']; ?> low-stock item(s)</a></li><?php endif; ?><?php if($x['unread_live_chat']>0):?><li><a href="/rbjsystem/ADMIN/live_chat.php"><?php echo $x['unread_live_chat']; ?> unread chat message(s)</a></li><?php endif; ?><?php if($x['pending_orders']===0&&$x['pending_payment_proofs']===0&&$x['rejected_payment_proofs']===0&&$x['pending_feedbacks']===0&&$x['low_stock_count']===0&&$x['unread_live_chat']===0):?><li>All clear. No urgent queue.</li><?php endif; ?></ul></section></div><div class="two"><section class="panel"><h3>Financial Snapshot (30d)</h3><ul><?php foreach($x['method_split'] as $m): ?><li><?php echo htmlspecialchars(str_replace('_',' ', $m['method'])); ?>: <strong><?php echo (int)$m['count']; ?></strong></li><?php endforeach; if(empty($x['method_split'])): ?><li>No completed payment data yet.</li><?php endif; ?><li>Sales 7 days: <strong>PHP <?php echo number_format($x['week_sales'],2); ?></strong></li></ul></section><section class="panel"><h3>Low Stock Watchlist</h3><?php if(!empty($low)): ?><table><thead><tr><th>Product</th><th>Stock</th><th>Category</th></tr></thead><tbody><?php foreach($low as $i): ?><tr><td><?php echo htmlspecialchars($i['name']); ?></td><td><strong><?php echo (int)$i['stock_quantity']; ?></strong></td><td><?php echo htmlspecialchars($i['category']); ?></td></tr><?php endforeach; ?></tbody></table><?php else: ?><div class="sub">No low-stock products.</div><?php endif; ?></section></div><section class="panel" style="margin-top:12px"><h3>Top Products by Revenue (30d)</h3><?php if(!empty($top)): ?><table><thead><tr><th>Product</th><th>Units</th><th>Revenue</th></tr></thead><tbody><?php foreach($top as $tp): ?><tr><td><?php echo htmlspecialchars($tp['name']); ?></td><td><?php echo (int)$tp['units']; ?></td><td>PHP <?php echo number_format((float)$tp['revenue'],2); ?></td></tr><?php endforeach; ?></tbody></table><?php else: ?><div class="sub">No order item data yet.</div><?php endif; ?></section><div class="charts"><div class="chart"><h3>Orders Trend</h3><div class="h"><canvas id="c1"></canvas></div></div><div class="chart"><h3>User Registrations</h3><div class="h"><canvas id="c2"></canvas></div></div><div class="chart"><h3>Feedback Trend</h3><div class="h"><canvas id="c3"></canvas></div></div></div><div class="two"><section class="panel"><h3>Recent Admin Activity</h3><ul><?php if(!empty($audit)): foreach($audit as $a): ?><li><strong><?php echo htmlspecialchars($a['username']); ?></strong> <?php echo htmlspecialchars($a['action']); ?> on <?php echo htmlspecialchars($a['entity_type']); ?><?php echo $a['entity_id']!==null?' #'.(int)$a['entity_id']:''; ?><small><?php echo date('M j, Y g:i A', strtotime($a['created_at'])); ?></small></li><?php endforeach; else: ?><li>No audit logs yet.</li><?php endif; ?></ul></section><section class="panel"><h3>Admin Notes</h3><?php if($msg!==''): ?><div style="padding:8px;border-radius:8px;background:#d5f5e3;color:#136c38;font-size:13px;margin-bottom:8px"><?php echo htmlspecialchars($msg); ?></div><?php endif; ?><?php if($err!==''): ?><div style="padding:8px;border-radius:8px;background:#fde2e2;color:#9a2b2b;font-size:13px;margin-bottom:8px"><?php echo htmlspecialchars($err); ?></div><?php endif; ?><form method="POST" action="dashboard_admin.php"><input type="hidden" name="csrf_token" value="<?php echo htmlspecialchars($csrf_token); ?>"><textarea name="dashboard_note" placeholder="Shift handoff notes...\n"><?php echo htmlspecialchars($note); ?></textarea><div style="margin-top:8px"><button type="submit" name="save_dashboard_note" style="padding:8px 10px;border:1px solid #111;background:#111;color:#fff;border-radius:8px;cursor:pointer">Save Note</button></div></form></section></div></main></div><script>const o=<?php $l=[];$d=[]; if($obm instanceof mysqli_result){while($r=$obm->fetch_assoc()){$l[]=date('M Y',strtotime($r['month'].'-01'));$d[]=(int)$r['count'];}} echo json_encode(['labels'=>$l,'data'=>$d]);?>;const u=<?php $l=[];$d=[]; if($ubm instanceof mysqli_result){while($r=$ubm->fetch_assoc()){$l[]=date('M Y',strtotime($r['month'].'-01'));$d[]=(int)$r['count'];}} echo json_encode(['labels'=>$l,'data'=>$d]);?>;const f=<?php $l=[];$d=[]; if($fbm instanceof mysqli_result){while($r=$fbm->fetch_assoc()){$l[]=date('M Y',strtotime($r['month'].'-01'));$d[]=(int)$r['count'];}} echo json_encode(['labels'=>$l,'data'=>$d]);?>;
const mk=(id,t,d,bg,b)=>new Chart(document.getElementById(id).getContext('2d'),{type:t,data:{labels:d.labels,datasets:[{data:d.data,backgroundColor:bg,borderColor:b,borderWidth:1,tension:.35,fill:t==='line'}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},scales:{y:{beginAtZero:true,ticks:{stepSize:1}}}}}); mk('c1','line',o,'rgba(47,128,237,.14)','#2f80ed'); mk('c2','bar',u,'rgba(39,174,96,.75)','#23935d'); mk('c3','line',f,'rgba(214,69,69,.14)','#d64545');
const n=v=>Number(v||0).toLocaleString(); const m=v=>'PHP '+Number(v||0).toLocaleString(undefined,{minimumFractionDigits:2,maximumFractionDigits:2});
function setK(k,v){document.querySelectorAll('[data-k="'+k+'"]').forEach(el=>el.textContent=(k.includes('sales')?m(v):n(v)));}
function refresh(){fetch('dashboard_admin.php?ajax=summary',{credentials:'same-origin'}).then(r=>r.json()).then(data=>{if(!data||!data.ok)return;const s=data.snapshot||{};['user_count','order_count','to_ship_orders','to_receive_orders','pending_orders','unread_live_chat'].forEach(k=>setK(k,s[k]||0));setK('today_sales',s.today_sales||0);setK('month_sales',s.month_sales||0);const at=document.getElementById('attention');if(at){let rows=[];if((s.pending_orders||0)>0)rows.push('<li><a href="/rbjsystem/ADMIN/orders_admin.php?status=to_pay">'+n(s.pending_orders)+' pending order(s)</a></li>');if((s.pending_payment_proofs||0)>0)rows.push('<li><a href="/rbjsystem/ADMIN/orders_admin.php?status=to_pay">'+n(s.pending_payment_proofs)+' pending payment proof(s)</a></li>');if((s.rejected_payment_proofs||0)>0)rows.push('<li><a href="/rbjsystem/ADMIN/orders_admin.php?status=to_pay">'+n(s.rejected_payment_proofs)+' rejected proof(s)</a></li>');if((s.pending_feedbacks||0)>0)rows.push('<li><a href="/rbjsystem/ADMIN/feedback_admin.php">'+n(s.pending_feedbacks)+' feedback pending review</a></li>');if((s.low_stock_count||0)>0)rows.push('<li><a href="/rbjsystem/ADMIN/products_admin.php">'+n(s.low_stock_count)+' low-stock item(s)</a></li>');if((s.unread_live_chat||0)>0)rows.push('<li><a href="/rbjsystem/ADMIN/live_chat.php">'+n(s.unread_live_chat)+' unread chat message(s)</a></li>');if(rows.length===0)rows=['<li>All clear. No urgent queue.</li>'];at.innerHTML=rows.join('');}
const ac=document.getElementById('activity'); if(ac&&Array.isArray(data.recent_orders)){let rows=data.recent_orders.map(r=>'<li>Order #'+n(r.id)+' from '+(r.username||'User')+'<small>'+new Date(r.created_at).toLocaleString()+'</small></li>'); rows.push('<li>'+n(data.feedback_today||0)+' feedback submission(s) today<small><a href="/rbjsystem/ADMIN/feedback_admin.php">Open moderation</a></small></li>'); ac.innerHTML=rows.join('');}}).catch(()=>{});} document.getElementById('refresh')?.addEventListener('click',refresh); setInterval(refresh,45000);
const dBtn=document.getElementById('density'); const root=document.getElementById('root'); const k='rbj_dash_compact'; function ad(){const c=localStorage.getItem(k)==='1'; root.classList.toggle('compact',c); dBtn.textContent=c?'Comfort':'Compact';} dBtn?.addEventListener('click',()=>{const c=localStorage.getItem(k)==='1'; localStorage.setItem(k,c?'0':'1'); ad();}); ad();
